/** Map WMO code → night SVG icon key */
export function nightIconKey(code) {
    if (code === 0)
        return 'night_clear';
    if (code === 1)
        return 'night_mainly_clear';
    if (code === 2)
        return 'night_partly_cloudy';
    if (code === 3)
        return 'night_overcast';
    if (code <= 48)
        return 'night_fog';
    if (code <= 67 || code <= 82)
        return 'night_rain';
    if (code <= 77)
        return 'night_snow';
    if (code >= 95)
        return 'night_thunder';
    return 'night_clear';
}
